fn find_smallest_index(
    vec_str_to_usize: Vec&lt;usize&gt;,
    start_index: usize,
    end_index: usize,
) -&gt; usize {
    let mut min = 36;
    let mut index = 0;

    for i in start_index..end_index + 1 {
        if min &gt; vec_str_to_usize[i as usize] {
            min = vec_str_to_usize[i as usize];
            index = i;
        }
    }

