    a.sort();

    for i in b.clone() {
        let ans = cmp::min(
            (a[(cmp::min(a.len() as isize - 1, binary_search(&a, i) as isize)) as usize] as isize
                - i as isize)
                .abs(),
            (a[(cmp::max(0, binary_search(&a, i) as isize - 1)) as usize] as isize - i as isize)
                .abs(),
