}

fn binary_search(a: &[usize], b: usize) -&gt; usize {
    let mut left = 0;
    let mut right = a.len();

    while left &lt; right {
        let mid = (left + right) / 2;
        if a[mid] == b {
            return mid;
        } else if a[mid] &lt; b {
            left = mid + 1;
        } else {
            right = mid;
        }
    }

    left
}
