        }
        saveWorkItem = task
        DispatchQueue.main.asyncAfter(deadline: .now() + 2, execute: task)
    }

    /// 明示的に即時保存したいときに呼ぶ
    func saveNow() {
        try? text.write(to: saveURL, atomically: true, encoding: .utf8)
    }
